request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?origId WHERE {
  ?model a bboExt:Model .
  ?model bbo:name ?modelName .
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  FILTER(CONTAINS(STR(?origId), "0b21c69687b64d8886fb7cc5dc56ff6c") || CONTAINS(STR(?normId), "0b21c69687b64d8886fb7cc5dc56ff6c"))
}
LIMIT 10

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?gw ?gwName ?gwDir ?source ?sourceName ?target ?targetName WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "0b21c69687b64d8886fb7cc5dc56ff6c" .
  ?gw a bboExt:ParallelGateway .
  ?gw tai:belongsTo+ ?model .
  OPTIONAL { ?gw bbo:name ?gwName . }
  OPTIONAL { ?gw bboExt:gatewayDirection ?gwDir . }
  OPTIONAL {
    ?flow a bbo:SequenceFlow .
    ?flow bbo:has_sourceRef ?gw .
    ?flow bbo:has_targetRef ?target .
    OPTIONAL { ?target bbo:name ?targetName . }
  }
  OPTIONAL {
    ?flow2 a bbo:SequenceFlow .
    ?flow2 bbo:has_sourceRef ?source .
    ?flow2 bbo:has_targetRef ?gw .
    OPTIONAL { ?source bbo:name ?sourceName . }
  }
}
LIMIT 50
